// Aeterna's Cultist sprite generator — ported directly from the actual
// Club Nile NFT/character generator in sevrin420/members-only's
// games/clubnile.html (HD_HEADS/HD_BODIES/HD_LEGS row data, color-ramp
// shading, the colored-outline pass, buildFrameHD). This is the same
// procedural system that renders that project's real character art —
// not an approximation of it. Only traitsForSeed() below is new,
// swapping the 1920s-speakeasy trait pool for a 1200 AD English monastic
// one (tonsure/plain hair, undyed-wool habits, an always-on hooded cloak)
// and dropping the giraffe/NFT-card/casino-specific code this project
// doesn't need.

function hex2rgb(h) {
  return [parseInt(h.slice(1, 3), 16), parseInt(h.slice(3, 5), 16), parseInt(h.slice(5, 7), 16)];
}
function mixc(a, b, t) {
  const A = hex2rgb(a), B = hex2rgb(b);
  const c = A.map((v, i) => Math.round(v + (B[i] - v) * t));
  return '#' + c.map(v => v.toString(16).padStart(2, '0')).join('');
}
/* LTTP shading: highlights lean warm cream, shadows lean cool plum —
   pushed hard for the bold cartoon read */
function ramp(base) {
  return { hi: mixc(base, '#fff3cf', 0.4), base, sh: mixc(base, '#2c1e3e', 0.48) };
}
/* material-specific ramps (adds per-character depth: different cloths catch light
   differently). linen = soft high-key; leather = glossy with a deep core shadow. */
function rampSoft(base)    { return { hi: mixc(base, '#fff6e2', 0.5),  base, sh: mixc(base, '#3a3050', 0.30) }; }
function rampLeather(base) { return { hi: mixc(base, '#ffe9c0', 0.52), base, sh: mixc(base, '#1a0e12', 0.55) }; }
/* undyed-wool habit: keep it earthen -- warm near-black shadow (not the cool
   plum used elsewhere) so browns stay brown and greys/blacks stay neutral */
function rampWool(base)    { return { hi: mixc(base, '#f3e8cc', 0.30), base, sh: mixc(base, '#181510', 0.52) }; }
/* saturation dial around a colour's own luma — <1 mutes, >1 enriches (rarity tint) */
function satAdjust(hex, f) {
  const c = hex2rgb(hex), L = 0.299 * c[0] + 0.587 * c[1] + 0.114 * c[2];
  const o = c.map(v => Math.max(0, Math.min(255, Math.round(L + (v - L) * f))));
  return '#' + o.map(v => v.toString(16).padStart(2, '0')).join('');
}
/* tiny deterministic per-token dye-lot jitter: small value + warm/cool skew (mag scales it) */
function jitterCol(hex, seed, mag) {
  mag = mag == null ? 1 : mag;
  const r = mulberry32(seed >>> 0), c = hex2rgb(hex);
  const v = 1 + (r() - 0.5) * 0.20 * mag, s = (r() - 0.5) * 18 * mag, cl = x => Math.max(0, Math.min(255, Math.round(x)));
  const o = [cl(c[0] * v + s), cl(c[1] * v), cl(c[2] * v - s)];
  return '#' + o.map(v => v.toString(16).padStart(2, '0')).join('');
}
/* symmetric halves: author 16 or 18 cells, mirror to 32 / 36 */
const sym = r => r + [...r].reverse().join('');
const symRows = rs => rs.map(sym);


