function paintRowsHD(g, rows, pal, yOff, xOff) {
  for (let y = 0; y < rows.length; y++) {
    const r = rows[y];
    for (let x = 0; x < r.length; x++) {
      const ch = r[x];
      if (ch === '.' || !pal[ch]) continue;
      g.fillStyle = pal[ch];
      g.fillRect((x + (xOff || 0)) * 0.5, y * 0.5 + yOff, 0.5, 0.5);
    }
  }
}
/* selective outline only — the material ramps carry the shading now */
function outlineHD(c) {
  const w = c.width, h = c.height;
  const g = c.getContext('2d');
  const src = g.getImageData(0, 0, w, h);
  const out = g.createImageData(w, h);
  const A = (x, y) => (x < 0 || y < 0 || x >= w || y >= h) ? 0 : src.data[(y * w + x) * 4 + 3];
  for (let y = 0; y < h; y++) for (let x = 0; x < w; x++) {
    const i = (y * w + x) * 4;
    if (src.data[i + 3] > 0) {
      out.data[i] = src.data[i]; out.data[i + 1] = src.data[i + 1];
      out.data[i + 2] = src.data[i + 2]; out.data[i + 3] = 255;
    } else if (A(x - 1, y) || A(x + 1, y) || A(x, y - 1) || A(x, y + 1)) {
      /* colored outline: a darkened tint of the fill it borders (richer than flat black) */
      let nr = 0, ng = 0, nb = 0, nc = 0;
      const add = (xx, yy) => { if (xx < 0 || yy < 0 || xx >= w || yy >= h) return; const j = (yy * w + xx) * 4; if (src.data[j + 3] > 0) { nr += src.data[j]; ng += src.data[j + 1]; nb += src.data[j + 2]; nc++; } };
      add(x - 1, y); add(x + 1, y); add(x, y - 1); add(x, y + 1);
      if (nc) { nr /= nc; ng /= nc; nb /= nc; }
      out.data[i] = Math.round(nr * 0.30 + 30 * 0.70);
      out.data[i + 1] = Math.round(ng * 0.30 + 18 * 0.70);
      out.data[i + 2] = Math.round(nb * 0.30 + 22 * 0.70);
      out.data[i + 3] = 255;
    }
  }
  g.putImageData(out, 0, 0);
}
function buildFrameHD(head, body, legs, pal, mirror, acc, dir) {
  const c = document.createElement('canvas');
  c.width = 40; c.height = 56;
  c.lw = 20; c.lh = 28;
  const g = c.getContext('2d');
  g.setTransform(2, 0, 0, 2, 0, 0);
  g.imageSmoothingEnabled = false;
  g.translate(1, 1);
  paintRowsHD(g, head, pal, 0, 0);      // 32 rows x 36 cells → 16lp of head
  paintRowsHD(g, body, pal, 16, 2);     // 12 rows x 32 cells → 6lp of body
  paintRowsHD(g, legs, pal, 22, 2);     // 8 rows x 32 cells → 4lp of legs
  if (acc) acc(g, dir, pal);            // cap / feather / favour, before outline
  g.setTransform(1, 0, 0, 1, 0, 0);
  outlineHD(c);
  if (!mirror) return c;
  const m = document.createElement('canvas');
  m.width = 40; m.height = 56;
  m.lw = 20; m.lh = 28;
  const mg = m.getContext('2d');
  mg.translate(40, 0); mg.scale(-1, 1);
  mg.drawImage(c, 0, 0);
  return m;
}
/* ---- head/face accessories, painted in logical head space over the frame.
   Head region: x 0..18 (centre 9), y 0..16; eyes ~y7-9; neck ~y15-16.
   Side view: face centres near x4. Kept within y >= -1 to avoid clipping. */
function blk(g, x, y, w, h, col) { if (!col) return; g.fillStyle = col; g.fillRect(x, y, w, h); }

const ACC_HEAD = {
  none() {},
  band(g, dir, a) {   /* gold flapper headband with a centre jewel */
    const cx = dir === 'side' ? 4 : 9, x0 = dir === 'side' ? 1 : 1.5, w = dir === 'side' ? 12 : 15;
    blk(g, x0, 3.6, w, 1.5, a.metal);
    blk(g, x0, 3.6, w, 0.5, a.metalHi);
    blk(g, cx - 1, 3.1, 2, 2, a.jewel);
    blk(g, cx - 0.4, 3.3, 0.8, 0.8, '#ffffff');
  },
  feather(g, dir, a) {   /* a single feather tucked into the hair (no headband) */
    const bx = dir === 'side' ? 8.5 : 13;
    blk(g, bx, -1, 1.1, 5.4, a.feather);
    blk(g, bx + 0.9, -1.4, 0.9, 4.0, a.feather);
    blk(g, bx + 0.3, -0.6, 0.6, 4.4, a.featherHi);
  },
  tiara(g, dir, a) {   /* slim gold circlet + crown points (legendary regalia only) */
    const cx = dir === 'side' ? 4 : 9, x0 = dir === 'side' ? 1.5 : 3, w = dir === 'side' ? 9 : 12;
    blk(g, x0, 3.5, w, 0.8, a.metal);
    blk(g, x0, 3.5, w, 0.3, a.metalHi);
    blk(g, cx - 2, 2.2, 0.8, 1.5, a.metal);
    blk(g, cx, 1.5, 0.8, 2.2, a.metal);
    blk(g, cx + 1.4, 2.2, 0.8, 1.5, a.metal);
    blk(g, cx - 0.2, 1.1, 1, 1, a.jewel);
  },
  plume(g, dir, a) {   /* a feather plume rising from the hair, held by a small clip (no band) */
    const cx = dir === 'side' ? 6 : 9;
    for (let i = 0; i < 6; i++) blk(g, cx - 1 + (i % 2), 4 - i, 1.6 - i * 0.12, 1, i < 4 ? a.feather : a.featherHi);
    blk(g, cx - 0.2, -1.4, 0.9, 6, a.featherHi);
    blk(g, cx - 1.1, 3.4, 2.4, 0.8, a.jewel);
  },
  bycocket(g, dir, a) {   // Robin Hood cap — pointed "beak" in profile, covering cap head-on
    const H = a.hat || '#2f6a38', HH = a.hatHi || '#3f8a48', HD = a.hatDark || '#1d4826';
    const FE = a.feather || '#d8c090', FH = a.featherHi || '#f2e6b8';
    if (dir === 'side') {
      // profile: cap covering the whole top of the head, with a beak jutting forward
      blk(g, 0.6, -1.0, 14.2, 3.8, H);                                 // crown front-to-back
      blk(g, 0.6, -1.0, 14.2, 1.0, HH);                                // top sheen
      blk(g, 12.6, -0.2, 2.6, 3.0, H);                                 // round the back of the crown
      blk(g, 0.6, 2.6, 14.0, 1.2, HD);                                 // rolled brim along the lower edge
      // forward-pointing beak — columns of decreasing height narrowing to the tip
      const cols = [[1.6,0.4,3.4],[0.6,0.8,2.8],[-0.3,1.2,2.1],[-1.0,1.6,1.3]];
      for (const [x,y,h] of cols) blk(g, x, y, 1.2, h, H);
      for (const [x,y,h] of cols) blk(g, x, y, 1.2, 0.6, HH);          // top-edge sheen on the beak
      blk(g, 13.4, -1.6, 1.0, 5.0, FE); blk(g, 14.2, -1.8, 0.9, 3.6, FE); // feather at the back
      blk(g, 13.8, -1.2, 0.6, 4.0, FH);
      return;
    }
    // front / back: cap covering the crown with an upturned brim (the point only shows in profile)
    blk(g, 2, -1.0, 14, 4.4, H);                // crown block
    blk(g, 2, -1.0, 14, 1.0, HH);               // top sheen
    blk(g, 1.4, 3.0, 15.2, 1.4, HD);            // rolled brim
    blk(g, 2.0, 2.4, 2.4, 1.1, HD);             // upturned brim corners
    blk(g, 13.6, 2.4, 2.4, 1.1, HD);
    if (dir !== 'up') {
      blk(g, 13.0, -1.6, 1.1, 5.6, FE); blk(g, 14.1, -1.8, 0.9, 4.2, FE); blk(g, 13.5, -1.2, 0.6, 4.6, FH);
    } else {
      blk(g, 13.0, -1.6, 1.1, 5.6, FE); blk(g, 13.5, -1.2, 0.6, 4.6, FH);
    }
  }
};
const ACC_FACE = {
  none() {},
  rose(g, dir, a) {   // a lady's favour / flower token pinned to the chest
    const x = dir === 'side' ? 3 : 6.5, y = 18.5;
    blk(g, x, y, 1.6, 1.6, a.jewel);
    blk(g, x + 0.4, y + 0.4, 0.7, 0.7, a.jewelHi);
  }
};
/* full-body cloak, drawn over the body/legs in sprite space (before the outline) */
function drawCloak(g, dir, cl) {
  const B = cl.base, H = cl.hi, S = cl.sh;
  if (dir === 'side') {
    blk(g, 7.5, 14.4, 6.8, 2.6, B); blk(g, 7.5, 14.4, 6.8, 0.8, H);   // shoulder / upper back
    blk(g, 9.0, 16.6, 5.6, 10, B);                                     // back drape to the feet
    blk(g, 9.0, 16.6, 1, 10, H); blk(g, 13.6, 16.6, 1, 10, S);
    blk(g, 6.6, 15.0, 2.0, 2.0, H);                                    // clasp at the throat
    return;
  }
  blk(g, 3.5, 14.3, 12, 2.7, B); blk(g, 3.5, 14.3, 12, 0.8, H);        // shoulder mantle / collar
  blk(g, 3.3, 16.6, 4.8, 10, B); blk(g, 3.3, 16.6, 1, 10, H);          // left panel to the feet
  blk(g, 10.9, 16.6, 4.8, 10, B); blk(g, 14.7, 16.6, 1, 10, S);        // right panel to the feet
  if (dir === 'up') blk(g, 7.7, 16.6, 3.4, 10, B);                     // back fully covered
  blk(g, 8.4, 14.8, 2.2, 2.2, H);                                      // clasp / brooch
}
function accPainter(t, ax) {
  const hf = ACC_HEAD[t.headAcc] || ACC_HEAD.none;
  const ff = ACC_FACE[t.faceAcc] || ACC_FACE.none;
  return (g, dir) => { if (ax.cloak) drawCloak(g, dir, ax.cloak); ff(g, dir, ax); hf(g, dir, ax); };
}

export function makeCharacterHD(t) {
  return makeCharacterHD_human(t);
}
function makeCharacterHD_human(t) {
  const skin = ramp(mixc('#e8c88a', t.skin || '#e8c88a', 0.22)), hat = rampWool(t.hat), coat = rampWool(t.coat);
  const pants = rampWool(t.pants), hair = ramp(t.hair), shoes = ramp(t.shoes);
  const shirt = rampSoft(t.shirt || '#f4ead2');
  const leather = rampLeather(t.leather || '#5a3a1d');
  const metalR = ramp(t.metal || '#d9c07a');
  const pal = {
    '2': hat.hi, H: hat.base, h: hat.sh,
    '1': skin.hi, S: skin.base, s: skin.sh,
    K: hair.base, k: hair.sh,
    '3': coat.hi, J: coat.base, j: coat.sh,
    L: mixc(t.trim || coat.sh, '#1a1220', 0.28),      // #11 contrast trim (lapels / tabard edge)
    C: shirt.base, R: t.tie || '#b02a3c',
    T: leather.base, Y: leather.hi,                   // per-character leather belt / jerkin
    G: metalR.hi, g: metalR.base,                     // #3 buttons / buckles match the token's metal
    E: t.iris || '#1a1216', W: '#fff6e6', M: t.mouth || '#8e4a42',
    B: pants.base, b: pants.sh, F: shoes.base, f: shoes.sh
  };
  const metal = ramp(t.metal || '#d9c07a');
  const jewel = ramp(t.jewel || '#b02a3c');
  const bycol = t.bycocketCol ? ramp(t.bycocketCol) : ramp('#2f6a38');
  const ax = {
    metal: metal.base, metalHi: metal.hi, dark: '#1c1620', band: t.jewel || '#7a1a26',
    jewel: jewel.base, jewelHi: jewel.hi, tie2: t.tie || '#1a1216',
    feather: (t.feather && ramp(t.feather).base) || '#e9dfce',
    featherHi: (t.feather && ramp(t.feather).hi) || '#fff8ea',
    hat: bycol.base, hatHi: bycol.hi, hatDark: mixc(bycol.sh, '#0d1a0e', 0.35),
    cloak: t.cloak ? rampWool(t.cloak) : null   // the habit's cloak is wool, not glossy
  };
  const acc = (t.cloak || (t.headAcc && t.headAcc !== 'none') || (t.faceAcc && t.faceAcc !== 'none'))
    ? accPainter(t, ax) : null;
  const legStyle = t.legs || (t.body === 'gown' ? 'gown' : ['dress','fringe','beaded','wrap'].includes(t.body) ? 'dress' : 'suit');
  const hd = HD_HEADS[t.head || 'fez'], bd = HD_BODIES[t.body || 'suit'], lg = HD_LEGS[legStyle] || HD_LEGS.suit;
  const out = {};
  out.down  = [0,1].map(f => buildFrameHD(hd.down, bd.front, lg.front[f], pal, false, acc, 'down'));
  out.up    = [0,1].map(f => buildFrameHD(hd.up,   bd.front, lg.front[f], pal, false, acc, 'up'));
  out.left  = [0,1].map(f => buildFrameHD(hd.side, bd.side,  lg.side[f],  pal, false, acc, 'side'));
  out.right = [0,1].map(f => buildFrameHD(hd.side, bd.side,  lg.side[f],  pal, true,  acc, 'side'));
  return out;
}
/* ================= unique Nile-era characters (NFT collection) =================
   A character is pure data: traitsForToken(id) is deterministic, so token #N
   always renders the same guest. Rendered fronts ship as a zip; when a wallet
   owns a token, the game loads that token's traits for the player sprite. */

function mulberry32(a) {
  return function () {
    a |= 0; a = (a + 0x6D2B79F5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// ===================== Aeterna trait pool (1200 AD English abbey) =====================
// Monastic dress, not Egyptian: undyed-wool habits in the colors real
// medieval orders wore -- Franciscan brown/grey, Cistercian undyed cream,
// Benedictine black -- with muted pewter/bronze fittings and subdued
// liturgical accent colors. Weathered, austere, earthen.
const AETERNA_SKIN = ['#f2cba0', '#e9b98c', '#d9ac84', '#c68a5e', '#a9714a', '#8a5a38'];
const AETERNA_HAIR = ['#2a1c12', '#3a2718', '#5a3a1e', '#4a4440', '#7a736a', '#161210'];
const AETERNA_ROBE = ['#4a3826', '#3a3630', '#26241f', '#5a4a34', '#2e2b24', '#463d2c', '#33302a'];
const AETERNA_GOLD = ['#8a8378', '#9a8a5a', '#6e685c', '#7a7066'];
const AETERNA_JEWEL = ['#7a2e28', '#3a5a3e', '#8a6a2a', '#4a3a5a', '#6a4a2a'];
const AETERNA_LINEN = ['#f4ead2', '#e8dcc0', '#d9c8a0', '#dfe0e2'];
const AETERNA_LEATHER = ['#5a3a1d', '#3d2712', '#6e4a24', '#4a3020'];
const AETERNA_IRIS = ['#241a12', '#1a2436', '#22321f', '#2a1a22'];
const HEADS_M = ['bald', 'bald', 'curly', 'wavy'];
const HEADS_F = ['wavy', 'curly', 'wavy', 'bald'];

// Deterministic Cultist traits from a wallet-id/name seed, in the same shape
// makeCharacterHD expects. Always cloaked (a hooded wool habit), tonsured or
// plain-haired (no Egyptian headwear), robe/cloak colors from the monastic
// wool palette above rather than jewel tones.
export function traitsForSeed(seed, sex) {
  let h = 2166136261;
  for (let i = 0; i < seed.length; i++) h = (Math.imul(h ^ seed.charCodeAt(i), 16777619)) >>> 0;
  const rnd = mulberry32(h);
  const pick = (arr) => arr[Math.floor(rnd() * arr.length)];
  const female = sex === 'female';

  const skin = jitterCol(pick(AETERNA_SKIN), (h * 2246822519) >>> 0, 0.3);
  const hair = pick(AETERNA_HAIR);
  const robe = jitterCol(pick(AETERNA_ROBE), (h * 40503 + 7) >>> 0, 0.8);
  const metal = pick(AETERNA_GOLD);
  const jewel = pick(AETERNA_JEWEL);
  const cloak = jitterCol(pick(AETERNA_ROBE), (h * 0x9e3779b1) >>> 0, 0.6);

  return {
    head: pick(female ? HEADS_F : HEADS_M),
    body: female ? pick(['dress', 'gown']) : pick(['suit', 'vest']),
    legs: female ? undefined : 'suit',
    skin, hair,
    hat: robe, coat: robe, pants: mixc(robe, '#0d0a12', 0.35),
    shoes: '#120d10',
    metal, jewel, tie: jewel,
    shirt: pick(AETERNA_LINEN),
    leather: pick(AETERNA_LEATHER),
    iris: pick(AETERNA_IRIS),
    trim: metal,
    mouth: '#8e4a42',
    feather: metal,
    headAcc: 'none',
    faceAcc: 'none',
    cloak,
  };
}

// The Abbot: the abbey's presiding figure. A tonsured elder in a fine near-
// black habit with a deep violet-black cloak and restrained gold trim (the
// mark of his office) -- distinguished from the plain wool of the brethren.
export function traitsForGuru() {
  return {
    head: 'bald',
    body: 'vest',
    legs: 'suit',
    skin: '#e6bd92', hair: '#8a837a',
    hat: '#2a2620', coat: '#2a2620', pants: '#201d17',
    shoes: '#120d10',
    metal: '#c9a13b', jewel: '#7a2e28', tie: '#7a2e28',
    shirt: '#e8dcc0', leather: '#3d2712', iris: '#1a1216', trim: '#c9a13b',
    mouth: '#8e4a42', feather: '#c9a13b',
    headAcc: 'none', faceAcc: 'none',
    cloak: '#332844',
  };
}
